module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [15:0] partial_product;
reg [7:0] multiplier;
reg [3:0] shift_count;

always @(*) begin
    partial_product = 16'b0;
    multiplier = B;
    shift_count = 4'b0;

    while (multiplier != 8'b0) begin
        if (multiplier[0] == 1'b1) begin
            partial_product = partial_product + (A << shift_count);
        end
        multiplier = multiplier >> 1;
        shift_count = shift_count + 1;
    end

    product = partial_product;
end

endmodule
